// 1. FUNZIONI DI SUPPORTO (Noise & Random)
// Devono essere definite fuori dal main

float random (in vec2 st) {
    return fract(sin(dot(st.xy, vec2(12.9898,78.233))) * 43758.5453123);
}

// Rumore di valore (Value Noise) 2D
float noise (in vec2 st) {
    vec2 i = floor(st);
    vec2 f = fract(st);

    // Interpolazione cubica (Smoothstep) per bordi morbidi
    vec2 u = f * f * (3.0 - 2.0 * f);

    float a = random(i);
    float b = random(i + vec2(1.0, 0.0));
    float c = random(i + vec2(0.0, 1.0));
    float d = random(i + vec2(1.0, 1.0));

    return mix(a, b, u.x) +
            (c - a)* u.y * (1.0 - u.x) +
            (d - b) * u.x * u.y;
}

// 2. MAIN IMAGE (Il tuo motore riconosce questa firma)
void mainImage( out vec4 fragColor, in vec2 fragCoord )
{
    // Calcolo coordinate UV normalizzate (0.0 - 1.0)
    vec2 uv = fragCoord.xy / iResolution.xy;
    float u = uv.x;
    float v = uv.y;

    // --- I TUOI PARAMETRI ORIGINALI ---
    float scale = 4.0;
    int octaves = 5;
    float cloudCover = 0.0; // Prova ad alzare questo (es. 0.1 o 0.2) per sfoltire

    // --- FIX INCOLLATURA (Mirroring) ---
    // Questo crea l'effetto specchio per rendere la texture "tileable"
    float u_fix = abs(u * 2.0 - 1.0);
    float v_fix = abs(v * 2.0 - 1.0);
    vec2 st = vec2(u_fix, v_fix) * scale;

    // --- FBM LOOP (Fractal Brownian Motion) ---
    //  Somma strati di rumore a frequenze crescenti e ampiezze decrescenti
    float value = 0.0;
    float amplitude = 0.5;
    float totalAmplitude = 0.0; // Per normalizzare alla fine

    for (int i = 0; i < 5; i++) {
        // Usiamo un loop fisso (GLSL preferisce) e rompiamo se serve
        if (i >= octaves) break; 

        value += amplitude * noise(st);
        st *= 2.0;       // Lacunarity: Raddoppia la frequenza
        totalAmplitude += amplitude;
        amplitude *= 0.5; // Gain: Dimezza l'ampiezza
    }

    // Normalizziamo il valore tra 0.0 e 1.0
    value /= totalAmplitude;

    // --- CONTRASTO E MASKING ---
    // Definiamo dove sono le nuvole rispetto al cielo vuoto
    float n = smoothstep(cloudCover + 0.2, cloudCover + 0.8, value);

    // --- OUTPUT COLORE ---
    // u_col1 e u_col2 sono le uniform globali del tuo programma
    vec3 color = mix(u_col1, u_col2, n);

    fragColor = vec4(color, 1.0);
}

